parameters.functionCode:
const analysis = $input.first().json;
const expected = $input.all()[1].json;

const variance = analysis.actualProgress - expected.expectedProgress;
const status = variance < -10 ? 'BEHIND' : variance > 10 ? 'AHEAD' : 'ON_TRACK';

return { ...analysis, variance, status, needsAttention: status === 'BEHIND' };

parameters.prompt:
Draft a construction site daily report for the Project Manager:

Site: {{ $json.siteName }}
Date: {{ $now }}
Actual Progress: {{ $json.actualProgress }}%
Expected: {{ $json.expectedProgress }}%
Variance: {{ $json.variance }}%
Status: {{ $json.status }}
Issues: {{ $json.issues }}

Format as professional report with action items.
